#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* positions = (int*) malloc(N * sizeof(int));
        int* directions = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &positions[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &directions[i]);
        }
        int Q;
        scanf("%d", &Q);
        while (Q--) {
            int I, T;
            scanf("%d %d", &I, &T);
            // Simulate the movement of the postman
            int position = positions[I];
            int direction = directions[I];
            int meets = 0;
            for (int i = 0; i < T; i++) {
                if (direction == 0) {
                    // Moving North
                    for (int j = I + 1; j < N; j++) {
                        if (positions[j] == position + 1) {
                            // Meet another postman
                            meets++;
                            direction = 1;
                            break;
                        }
                    }
                    if (direction == 0) {
                        position++;
                    }
                } else {
                    // Moving South
                    for (int j = I - 1; j >= 0; j--) {
                        if (positions[j] == position - 1) {
                            // Meet another postman
                            meets++;
                            direction = 0;
                            break;
                        }
                    }
                    if (direction == 1) {
                        position--;
                    }
                }
            }
            printf("%d %d\n", position, meets);
        }
        free(positions);
        free(directions);
    }
    return 0;
}

